wave_0_per_point:
t1 = sample+time*.2;

x = .35* sin (6*t1) ;
my = .35* cos (3*t1)* sin (-10+20*sample) ;
mz = .35* cos (7*t1) * cos (-5+10*sample) ;


/////// rotations... by flexi

d = 1;
zoom = 1;

w1 = .3*time;
w2 = .1*time;
w3 = .2*time;

x1 = cos(w1)*mx + sin(w1)*my;
y1 = -sin(w1)*mx + cos(w1)*my;
z1 = mz;

x2 = cos(w2)*x1 + sin(w2)*z1;
z2 = -sin(w2)*x1 + cos(w2)*z1;
y2 = y1;

y3 = cos(w3)*y2 + sin(w3)*z2;
z3 = -sin(w3)*y2 + cos(w3)*z2;
x3 = x2;


// perspective calculation

l = sqrt(x3*x3 + y3*y3);
w = atan2(x3,y3);
p = tan(asin(1) + atan2(d+z3,l));
d = sqrt(x3*x3 + y3*y3 + (z3+d)*(z3+d));

my_x = zoom*sin(w)*p;
my_y = zoom*cos(w)*p;

x = 0.5 + my_x;
y = 0.5 + my_y;

